INSERT INTO `notifications` VALUES (4,'Chào đón đại lễ 30/4 -1/5, giảm giá ưu đãi đến 10%','Chào đón đại lễ 30/4 -1/5, giảm giá ưu đãi.\nNhân dịp chào đón đại lễ 30/4 -1/5 trang web www.bomrautft.com giảm giá đặc biệt cho tất cả tài khoản, MUA NGAY số lượng có hạn.\n\nAnh em lựa chọn tài khoản yêu thích và liên lạc cho Bờm Râu để được nhận ưu đãi qua zép lào : 0338180818 (Bờm râu ).','https://res.cloudinary.com/dvvg0axht/image/upload/v1779728387/bomrau/f4re6rkvwtzjtsriy3rm.webp','news',0,1,'2026-05-26 03:48:15','2026-05-28 17:41:39');
