DROP TABLE IF EXISTS `products`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `products` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `category_id` int unsigned NOT NULL,
  `extra_categories` json DEFAULT NULL,
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `image_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `price` decimal(15,0) NOT NULL COMMENT 'Gi?? b??n (VND)',
  `original_price` decimal(15,0) NOT NULL COMMENT 'Gi?? g???c ch??a gi???m (VND)',
  `discount_percent` tinyint unsigned NOT NULL DEFAULT '0' COMMENT 'Ph???n tr??m gi???m gi?? (0-100)',
  `fake_remaining_count` int unsigned NOT NULL DEFAULT '0' COMMENT 'S??? l?????ng ???o c??n l???i',
  `fake_sold_count` int unsigned NOT NULL DEFAULT '0' COMMENT 'S??? l?????ng ???o ???? b??n',
  `pet_tim` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `san_tim` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'S??? s??n t??m / th??ng tin s??n',
  `chuong` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'S??? ch?????ng / th??ng tin ch?????ng',
  `extra_info` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Th??ng tin b??? sung',
  `status` enum('available','hidden') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'available',
  `is_pinned` tinyint(1) NOT NULL DEFAULT '0',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  KEY `idx_products_category` (`category_id`) USING BTREE,
  KEY `idx_products_status` (`status`) USING BTREE,
  KEY `idx_products_price` (`price`) USING BTREE,
  CONSTRAINT `fk_products_category` FOREIGN KEY (`category_id`) REFERENCES `categories` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1187 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC;
